import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Alert, Button, EmptyState, FilterInput, LoadingBar, MultiSelect, Stack, Tag, Text } from '@grafana/ui';
import { AppEvents } from '@grafana/data';
import { getAppEvents } from '@grafana/runtime';
import { listTemplates } from '../api/templates';
import { TemplateCard } from '../components/TemplateCard';
import type { Template } from '../types';

const PLUGIN_ROOT = '/a/gregoor-private-marketplace-app';

export function Gallery() {
  const navigate = useNavigate();
  const appEvents = getAppEvents();

  const [templates, setTemplates] = useState<Template[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [selectedDatasourceTypes, setSelectedDatasourceTypes] = useState<string[]>([]);

  const fetchTemplates = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      setTemplates(await listTemplates());
    } catch (loadError) {
      const message = loadError instanceof Error ? loadError.message : 'Failed to load templates';
      setError(message);
      appEvents.publish({
        type: AppEvents.alertError.name,
        payload: ['Failed to load templates', message],
      });
    } finally {
      setLoading(false);
    }
  }, [appEvents]);

  useEffect(() => {
    fetchTemplates();
  }, [fetchTemplates]);

  const allTags = useMemo(() => {
    const uniqueTags = new Set<string>();
    templates.forEach((template) => template.metadata.tags?.forEach((tag) => uniqueTags.add(tag)));
    return Array.from(uniqueTags).sort();
  }, [templates]);

  const allDatasourceTypes = useMemo(() => {
    const uniqueTypes = new Set<string>();
    templates.forEach((template) =>
      template.metadata.requiredDatasources?.forEach((datasource) => uniqueTypes.add(datasource.type))
    );
    return Array.from(uniqueTypes).sort();
  }, [templates]);

  const filteredTemplates = useMemo(() => {
    const normalizedQuery = searchQuery.trim().toLowerCase();

    return templates.filter((template) => {
      const searchableText = [
        template.metadata.title,
        template.metadata.shortDescription,
        ...(template.metadata.tags ?? []),
      ]
        .join(' ')
        .toLowerCase();

      if (normalizedQuery && !searchableText.includes(normalizedQuery)) {
        return false;
      }

      if (
        selectedTags.length > 0 &&
        !selectedTags.every((tag) => template.metadata.tags?.includes(tag))
      ) {
        return false;
      }

      const templateDatasourceTypes = (template.metadata.requiredDatasources ?? []).map((item) => item.type);
      if (
        selectedDatasourceTypes.length > 0 &&
        !selectedDatasourceTypes.every((type) => templateDatasourceTypes.includes(type))
      ) {
        return false;
      }

      return true;
    });
  }, [searchQuery, selectedDatasourceTypes, selectedTags, templates]);

  return (
    <div style={{ padding: '24px' }}>
      <Stack justifyContent="space-between" alignItems="flex-start" wrap="wrap" gap={2}>
        <Stack direction="column" gap={0.5}>
          <Text element="h1" variant="h2">
            Dashboard Marketplace
          </Text>
          <Text color="secondary">
            Browse, import, and publish reusable Grafana dashboard templates.
          </Text>
        </Stack>

        <Button icon="upload" variant="primary" onClick={() => navigate(`${PLUGIN_ROOT}/upload`)}>
          Upload template
        </Button>
      </Stack>

      <div style={{ margin: '20px 0' }}>
        <Stack direction="row" gap={2} wrap="wrap">
          <div style={{ minWidth: '280px', flex: 1 }}>
            <FilterInput
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by title, description, or tags..."
            />
          </div>

          <div style={{ minWidth: '220px' }}>
            <MultiSelect
              options={allTags.map((tag) => ({ label: tag, value: tag }))}
              value={selectedTags.map((tag) => ({ label: tag, value: tag }))}
              onChange={(items) => setSelectedTags(items.map((item) => String(item.value)))}
              placeholder="Filter by tags"
              closeMenuOnSelect={false}
              isClearable
            />
          </div>

          <div style={{ minWidth: '240px' }}>
            <MultiSelect
              options={allDatasourceTypes.map((type) => ({ label: type, value: type }))}
              value={selectedDatasourceTypes.map((type) => ({ label: type, value: type }))}
              onChange={(items) => setSelectedDatasourceTypes(items.map((item) => String(item.value)))}
              placeholder="Filter by datasource"
              closeMenuOnSelect={false}
              isClearable
            />
          </div>

          {(searchQuery || selectedTags.length > 0 || selectedDatasourceTypes.length > 0) && (
            <Button
              variant="secondary"
              onClick={() => {
                setSearchQuery('');
                setSelectedTags([]);
                setSelectedDatasourceTypes([]);
              }}
            >
              Clear filters
            </Button>
          )}
        </Stack>
      </div>

      {selectedTags.length > 0 && (
        <div style={{ marginBottom: '16px' }}>
          <Stack gap={1} wrap="wrap">
            {selectedTags.map((tag) => (
              <Tag key={tag} name={tag} onClick={() => setSelectedTags((current) => current.filter((item) => item !== tag))} />
            ))}
          </Stack>
        </div>
      )}

      {loading && <LoadingBar width={320} />}

      {!loading && error && (
        <Alert title="Could not load templates" severity="error">
          <div style={{ marginBottom: '12px' }}>{error}</div>
          <Button size="sm" variant="secondary" onClick={fetchTemplates}>
            Retry
          </Button>
        </Alert>
      )}

      {!loading && !error && templates.length === 0 && (
        <EmptyState
          variant="call-to-action"
          message="No templates available yet"
          button={
            <Button icon="upload" variant="primary" onClick={() => navigate(`${PLUGIN_ROOT}/upload`)}>
              Upload your first template
            </Button>
          }
        >
          <Text color="secondary">Start by publishing a dashboard template for your team.</Text>
        </EmptyState>
      )}

      {!loading && !error && templates.length > 0 && filteredTemplates.length === 0 && (
        <EmptyState variant="not-found" message="No templates match the current filters">
          <Button
            variant="secondary"
            onClick={() => {
              setSearchQuery('');
              setSelectedTags([]);
              setSelectedDatasourceTypes([]);
            }}
          >
            Clear filters
          </Button>
        </EmptyState>
      )}

      {!loading && !error && filteredTemplates.length > 0 && (
        <>
          <div style={{ marginBottom: '16px' }}>
            <Text color="secondary">
              {filteredTemplates.length} template{filteredTemplates.length === 1 ? '' : 's'}
              {filteredTemplates.length !== templates.length ? ` (filtered from ${templates.length})` : ''}
            </Text>
          </div>

          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
              gap: '16px',
            }}
          >
            {filteredTemplates.map((template) => (
              <TemplateCard
                key={template.metadata.id}
                template={template}
                onClick={() => navigate(`${PLUGIN_ROOT}/template/${template.metadata.id}`)}
              />
            ))}
          </div>
        </>
      )}
    </div>
  );
}
